    const SYSTEM_BASE = `You are an expert Bitcoin Core reviewer (C++20 and related build, test, and tooling).
	Be skeptical. Assume subtle bugs exist until proven otherwise.
	Prioritize consensus safety, determinism, and security. Consider worst-case behavior and DoS angles.
	Do not assume the change is a good idea or worth doing. Explicitly consider whether it is desirable, whether it is worth the complexity/performance/maintenance cost, and what higher-priority work it might displace.
	This output is a private review aid. Do NOT draft a PR review comment and do NOT propose posting anything. Avoid "LGTM/approve" style conclusions.
	Prefer interactive assistance: ask high-leverage questions that help the human reviewer do their own review.
	Look for undefined behavior, lifetime and ownership bugs, memory alignment pitfalls, signedness and integer overflow, endianness, boundary conditions, thread safety, lock ordering, atomic ordering, and API misuse.
	Verify lock annotations (EXCLUSIVE_LOCKS_REQUIRED, LOCKS_EXCLUDED) match actual locking. Check that AssertLockHeld calls agree with annotations. Flag RecursiveMutex where Mutex would suffice.
	Ensure cryptographic code uses constant-time operations where needed. Verify all user/network input is validated before use.
	Check for inconsistencies between code, comments, naming, and behavior.
	Each commit in a stacked PR should be self-contained: it should compile, preserve coherent behavior, and justify the transition it introduces. Transitional commits can prepare for later work, but should not rely on future commits for correctness.
Scripted-diff commits (mechanical renames) should be verifiable independently and not mix behavioral changes. Check for -BEGIN VERIFY SCRIPT- / -END VERIFY SCRIPT- markers and whether the script handles overlapping patterns correctly.
For benchmarks and performance changes, note when inputs may not be representative or when harness overhead can dominate measurement. Prefer deterministic, reproducible setups. When benchmark input data changes intentionally, expect and explain baseline impact.
Commit messages should describe the problem first, then the change. Prefer short narrative prose over lists. Use backticks around symbol and command names. Avoid forward references to future commits.
Track scope carefully: mechanical renames should not be mixed with behavior changes, benchmark input changes should be separate from API changes, build-system fixes should be coupled with the functional change they unblock.
Bitcoin Core developer-notes conventions to watch for: snake_case variables, m_ member prefix, g_ global prefix, PascalCase functions, no using namespace, no std::map::operator[] for reads (use .find()), Mutex over RecursiveMutex, explicit constructors, std::optional over sentinels, named boolean args (Foo(/*flag=*/true)).
Prefer small, local fixes over refactors. Avoid speculative redesigns.
When there is a tradeoff, give the best argument for and against, then ask the single most important follow-up question.
Do not self-censor minor issues. Label them as minor if needed, but still report them.
Always present problems before solutions, questions before answers. Explain outside-in: start at the highest level, briefly introduce any new concept or term before using it, then progressively zoom into the problem until it is clear. Only after the problem is understood, explain why it matters. Only then present the solution.
Use \`backticks\` for every symbol, function, type, variable, file, and class name (e.g. "Guards \`SetStdinEcho\` with \`StdinTerminal()\` early return"). Explain every abbreviation and domain-specific term on first use.
When your output appears next to the original text (commit message, PR description, or user comment), do NOT repeat what the original already says. Add what is missing: context, implications, risks, or background the reader needs.
Task-specific instructions and requested output schemas override these default style rules.
Ground factual claims in the provided page context, diff, comments, or clearly labeled inference. If evidence is missing, say what is missing instead of guessing.
Before finalizing, check correctness, grounding, and formatting against the requested output contract.
Keep it concise and blunt. Skip obvious observations. Use plain ASCII. No em dashes. Use bullets or numbered lists only when the task's output contract asks for them or they materially improve scanability.`;

    function getAnalysisMode(path = location.pathname) {
        if (/\/pull\/\d+\/commits\/[0-9a-f]+/.test(path)) return ANALYSIS_MODES.commit;
        if (/\/pull\/\d+\/changes\/[0-9a-f]+/.test(path)) return ANALYSIS_MODES.commit;
        if (/\/commit\/[0-9a-f]{7,40}(?:[/?#]|$)/i.test(path)) return ANALYSIS_MODES.commit;
        if (/\/pull\/\d+\/commits\/?$/.test(path)) return ANALYSIS_MODES.commits;
        return ANALYSIS_MODES.pr;
    }

    function getProviderInstructions(active) {
        const instructions = {};
        for (const key of LLM_INSTRUCTION_KEYS) {
            instructions[key] = GM_getValue(`llm_instr_${active}_${key}`, '');
        }
        return instructions;
    }

    function isPromptRecipe(recipe) {
        return PROMPT_RECIPE_KEYS.has(recipe);
    }

    function isCopyableRecipe(recipe) {
        return COPYABLE_RECIPE_KEYS.has(recipe);
    }

    function isShiftCopyAction(action) {
        return SHIFT_COPY_ACTION_KEYS.has(action);
    }

    function getRobotRecipeTitle(recipe) {
        return ROBOT_RECIPE_ACTIONS.find(({ key }) => key === recipe)?.label || 'Chat';
    }

    function getLLMConfig() {
        const active = getActiveProvider();
        const providerConfig = {};
        for (const name of Object.keys(PROVIDER_META)) {
            providerConfig[name] = { key: GM_getValue(providerKeyStorageKey(name), ''), model: LLM_MODELS[name] };
        }
        return {
            ...providerConfig,
            active,
            instructions: getProviderInstructions(active),
            includeFullPatch: GM_getValue('llm_include_patch', true),
            cacheEnabled: GM_getValue('llm_cache_enabled', true),
        };
    }

    function isProviderAvailable(name) {
        const cfg = getLLMConfig()[name];
        return !!cfg?.key;
    }

    function getTooltipLLMTarget() {
        // Selection helpers use the same provider/model as the rest of ACKtopus.
        // Keeping this deterministic improves prompt caching and avoids surprising
        // "why is this using a different model?" behavior.
        const cfg = getLLMConfig();
        const provider = cfg.active;
        const model = cfg[provider]?.model || '';
        return { provider, model };
    }

    // --- Cache ---

    function cacheKey(provider, pr, id) {
        const kind = pageKind() || 'pull';
        const model = getLLMConfig()[provider]?.model || 'default';
        return `llm_cache_${kind}_${pr.owner}_${pr.repo}_${pr.pr}_${provider}_${model}_${id}`;
    }

    function prInfographicCachePrefix(pr) {
        return `llm_infographic_${pr.owner}_${pr.repo}_${pr.pr}_`;
    }

    function prInfographicCacheKey(pr, headSha, scope = 'pr') {
        const version = `v${PR_INFOGRAPHIC_PROMPT_VERSION}`;
        const sha = /^[0-9a-f]{7,40}$/i.test(String(headSha || '')) ? String(headSha).toLowerCase() : 'unknown';
        const scopeKey = scope === 'commit' ? 'commit' : 'pr';
        return `${prInfographicCachePrefix(pr)}${scopeKey}_${OPENAI_IMAGE_MODEL}_${OPENAI_IMAGE_SIZE}_${OPENAI_IMAGE_QUALITY}_${OPENAI_IMAGE_FORMAT}_${OPENAI_IMAGE_BACKGROUND}_${OPENAI_IMAGE_MODERATION}_${version}_${sha}`;
    }

    function robotChatHistoryKeyForPage(ctx = parsePageContext() || currentCommitRepoContext?.() || null) {
        const pageKey =
            ctx?.owner && ctx?.repo ? `${ctx.owner}/${ctx.repo}${ctx.pr ? `#${ctx.pr}` : ''}` : location.pathname;
        return `ack_robot_chat_threads:${pageKey}`;
    }

    function clearRobotChatHistoryForPage() {
        const key = robotChatHistoryKeyForPage();
        const existing = GM_getValue(key, null);
        if (existing == null) return 0;
        GM_deleteValue(key);
        window.dispatchEvent(new CustomEvent(ROBOT_CHAT_HISTORY_CLEARED_EVENT, { detail: { key } }));
        return 1;
    }

    function normalizeInfographicCacheValue(value) {
        if (!value) return null;
        if (typeof value === 'string') return { b64: value, mimeType: `image/${OPENAI_IMAGE_FORMAT}` };
        if (value.b64) return value;
        return null;
    }

    function getInfographicCache(pr, headSha, scope = 'pr') {
        if (!getLLMConfig().cacheEnabled) return null;
        const key = prInfographicCacheKey(pr, headSha, scope);
        const cached = normalizeInfographicCacheValue(GM_getValue(key, null));
        if (cached) recordCacheTimestamp(key);
        return cached;
    }

    function setInfographicCache(pr, headSha, value, scope = 'pr') {
        if (!getLLMConfig().cacheEnabled) return;
        const key = prInfographicCacheKey(pr, headSha, scope);
        GM_setValue(key, value);
        recordCacheTimestamp(key);
    }

    function getCache(provider, pr, id) {
        if (!getLLMConfig().cacheEnabled) return null;
        return GM_getValue(cacheKey(provider, pr, id), null);
    }

    function setCache(provider, pr, id, value) {
        if (!getLLMConfig().cacheEnabled) return;
        const key = cacheKey(provider, pr, id);
        GM_setValue(key, value);
        recordCacheTimestamp(key);
    }

    function recordCacheTimestamp(key) {
        const ts = GM_getValue('llm_cache_timestamps', {});
        ts[key] = Date.now();
        GM_setValue('llm_cache_timestamps', ts);
    }

    function evictStaleCache() {
        if (typeof GM_listValues !== 'function') return;
        const THIRTY_DAYS = 30 * 24 * 60 * 60 * 1000;
        const now = Date.now();
        const ts = GM_getValue('llm_cache_timestamps', {});
        const keys = GM_listValues();
        let evicted = 0;
        for (const k of keys) {
            const isLLM =
                k.startsWith('llm_cache_') ||
                k.startsWith('llm_prompt_') ||
                k.startsWith('llm_lightbulb_') ||
                k.startsWith('llm_explain_') ||
                k.startsWith('llm_pr_overview_') ||
                k.startsWith('llm_lightbulb_autoopen_') ||
                k.startsWith('llm_infographic_');
            if (!isLLM || k === 'llm_cache_timestamps') continue;
            const age = ts[k] ? now - ts[k] : Infinity;
            if (age > THIRTY_DAYS) {
                GM_deleteValue(k);
                delete ts[k];
                evicted++;
            }
        }
        if (evicted > 0) GM_setValue('llm_cache_timestamps', ts);
    }

    evictStaleCache();

    function clearCacheForPR() {
        const pr = parsePageContext();
        if (!pr) return 0;
        const kind = pageKind() || 'pull';
        const prefix = `llm_cache_${kind}_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const promptPrefix = `llm_prompt_${kind}_${pr.owner}_${pr.repo}_${pr.pr}_`;
        // Also clear legacy keys without kind prefix
        const legacyPrefix = `llm_cache_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const legacyPromptPrefix = `llm_prompt_${pr.owner}_${pr.repo}_${pr.pr}_`;
        // Clear lightbulb and explain caches too
        const lightbulbPrefix = `llm_lightbulb_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const explainPrefix = `llm_explain_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const overviewPrefix = `llm_pr_overview_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const autoOpenPrefix = `llm_lightbulb_autoopen_${pr.owner}_${pr.repo}_${pr.pr}_`;
        const infographicPrefix = prInfographicCachePrefix(pr);
        const keys = typeof GM_listValues === 'function' ? GM_listValues() : [];
        let count = 0;
        keys.forEach((k) => {
            if (
                k.startsWith(prefix) ||
                k.startsWith(promptPrefix) ||
                k.startsWith(legacyPrefix) ||
                k.startsWith(legacyPromptPrefix) ||
                k.startsWith(lightbulbPrefix) ||
                k.startsWith(explainPrefix) ||
                k.startsWith(overviewPrefix) ||
                k.startsWith(autoOpenPrefix) ||
                k.startsWith(infographicPrefix)
            ) {
                GM_deleteValue(k);
                count++;
            }
        });
        count += clearRobotChatHistoryForPage();
        return count;
    }

    function clearAllCaches() {
        const keys = typeof GM_listValues === 'function' ? GM_listValues() : [];
        let count = 0;
        // Only clear actual cache entries - never API keys, instructions, or user preferences
        const isCacheKey = (k) =>
            k.startsWith('llm_explain_') ||
            k.startsWith('llm_lightbulb_') ||
            k.startsWith('llm_pr_overview_') ||
            k.startsWith('llm_lightbulb_autoopen_') ||
            k.startsWith('llm_infographic_') ||
            k.startsWith('llm_cache_') ||
            k.startsWith('llm_prompt_') ||
            k.startsWith('pr_comment_count_') ||
            k.startsWith('org_members_') ||
            k.startsWith('repo_members_') ||
            k.startsWith('pr_context_') ||
            k.startsWith('commitlist_') ||
            k === 'llm_cache_timestamps';
        keys.forEach((k) => {
            if (isCacheKey(k)) {
                GM_deleteValue(k);
                count++;
            }
        });
        // Also clear in-memory caches
        Object.keys(_orgMemberCache).forEach((k) => delete _orgMemberCache[k]);
        _reviewCommitMap = null;
        console.log(`ACKtopus: clearAllCaches - removed ${count} GM entries + in-memory caches`);
        return count;
    }

    function factoryReset() {
        const keys = typeof GM_listValues === 'function' ? GM_listValues() : [];
        const keep = new Set([...providerKeyStorageKeys(), 'github_pat']);
        let count = 0;
        keys.forEach((k) => {
            if (!keep.has(k)) {
                GM_deleteValue(k);
                count++;
            }
        });
        Object.keys(_orgMemberCache).forEach((k) => delete _orgMemberCache[k]);
        _reviewCommitMap = null;
        console.log(`ACKtopus: factoryReset - removed ${count} GM entries (kept API keys)`);
        return count;
    }

    // --- Config Panel ---

    function validateKey(provider, key, statusEl, updateHelp) {
        if (!key.trim()) {
            statusEl.textContent = '';
            if (updateHelp) updateHelp('invalid');
            return;
        }
        statusEl.textContent = '⏳';
        statusEl.style.color = '#848d97';

        const onResult = (ok, msg) => {
            statusEl.textContent = ok ? '✅' : '❌';
            statusEl.style.color = ok ? '#3fb950' : '#f85149';
            statusEl.title = msg;
            if (updateHelp) updateHelp(ok ? 'valid' : 'invalid');
        };

        const onWarn = (msg, state = 'valid') => {
            statusEl.textContent = '⚠️';
            statusEl.style.color = '#d29922';
            statusEl.title = msg;
            if (updateHelp) updateHelp(state);
        };

        const classifyResponse = (r) => {
            const responseText = r.responseText || '';
            if (r.status >= 200 && r.status < 300) return { ok: true, state: 'valid', msg: 'Valid' };
            if (r.status === 401) return { ok: false, state: 'invalid', msg: 'Invalid API key' };
            if (r.status === 403) return { ok: false, state: 'invalid', msg: 'Key forbidden, check permissions' };
            if (r.status === 404) return { ok: false, state: 'invalid', msg: 'Model not available' };
            if (provider === 'claude' && responseText.includes('credit')) {
                return { ok: true, warn: true, state: 'nofunds', msg: 'No credits, add funds' };
            }
            if (provider !== 'claude' && r.status === 429 && responseText.includes('quota')) {
                return { ok: true, warn: true, state: 'nofunds', msg: 'Quota exceeded, add funds' };
            }
            if (provider !== 'claude' && r.status === 429) {
                return { ok: true, warn: true, state: 'valid', msg: 'Rate limited, try again shortly' };
            }
            if (provider === 'claude' && r.status === 529) {
                return { ok: true, warn: true, state: 'valid', msg: 'API temporarily overloaded' };
            }
            if (provider === 'claude' && r.status === 400) return { ok: true, state: 'valid', msg: 'Key accepted' };
            if (r.status === 400) return { ok: false, state: 'invalid', msg: `400: ${parseProviderError(r)}` };
            return { ok: false, state: 'invalid', msg: `HTTP ${r.status}` };
        };

        const validationFailure = (target, prefix, event) => ({
            ...target,
            ok: false,
            state: 'invalid',
            msg: `${prefix}: ${formatTransportErrorDetails(event)}`,
        });

        const validateTarget = (target) =>
            new Promise((resolve) => {
                GM_xmlhttpRequest({
                    ...providerValidationRequest(provider, key, target),
                    onload: (r) => resolve({ ...target, ...classifyResponse(r) }),
                    onerror: (e) => resolve(validationFailure(target, 'Network error', e)),
                    ontimeout: (e) => resolve(validationFailure(target, 'Timed out', e)),
                });
            });

        const targets = getProviderValidationTargets(provider);
        Promise.all(targets.map(validateTarget)).then((results) => {
            const label = (r) => r.label || r.model;
            const failed = results.filter((r) => !r.ok);
            const warned = results.filter((r) => r.ok && r.warn);
            const primaryFailed = failed.find((r) => r.model === LLM_MODELS[provider]) || null;
            const checkedModels = results.map(label).join(', ');
            const describeResults = (items) => items.map((r) => `${label(r)} (${r.msg})`).join('; ');
            if (primaryFailed) {
                onResult(
                    false,
                    `Primary model failed: ${label(primaryFailed)} (${primaryFailed.msg}). Checked: ${checkedModels}`,
                );
            } else if (failed.length) {
                onWarn(
                    `Warning: Secondary model unavailable: ${describeResults(
                        failed,
                    )}. Primary model is usable. Checked: ${checkedModels}`,
                    'valid',
                );
            } else if (warned.length) {
                const state = warned.some((r) => r.state === 'nofunds') ? 'nofunds' : 'valid';
                onWarn(`Warning: ${describeResults(warned)}. Checked: ${checkedModels}`, state);
            } else {
                onResult(true, `Valid models: ${checkedModels}`);
            }
        });
    }

    function fmtTokens(n) {
        if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
        if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
        return String(n);
    }

    function fmtCost(provName, inputTokens, outputTokens) {
        const m = PROVIDER_META[provName];
        if (!m) return '';
        const cost = (inputTokens * m.inputPrice + outputTokens * m.outputPrice) / 1_000_000;
        if (cost < 0.005) return '$0.00';
        if (cost < 1) return `$${cost.toFixed(2)}`;
        return `$${cost.toFixed(2)}`;
    }

