    ackTest('qsa is exported', () => {
        ackEq(typeof qsa, 'function');
    });

    ackTest('qsa on document returns descendants', () => {
        const results = qsa(document, 'body');
        ackAssert(Array.isArray(results), 'qsa should return an array');
        ackAssert(results.length >= 1, 'qsa(document, body) should find at least one element');
        ackEq(results[0], document.body, 'qsa(document, body) should return document.body');
    });

    ackTest('qsa checks root itself with matches()', () => {
        const root = document.createElement('div');
        root.className = 'qsa-root';
        root.innerHTML = `<div class="qsa-root"></div>`;
        const results = qsa(root, '.qsa-root');
        ackEq(results.length, 2, 'qsa should include root + descendant match');
        ackEq(results[0], root, 'root match should be first');
    });

    ackTest('qsa skips matches check when root is document', () => {
        let called = false;
        const prev = document.matches;
        let didPatch = false;
        try {
            document.matches = () => {
                called = true;
                throw new Error('document.matches should not be called by qsa');
            };
            didPatch = true;
        } catch (_) {
            // If we can't patch document.matches (unlikely), just fall back to
            // behavior checks below.
        }
        try {
            const results = qsa(document, 'body');
            ackEq(results[0], document.body, 'qsa(document, body) should still work');
            ackAssert(!called, 'qsa must not call document.matches');
        } finally {
            if (didPatch) {
                if (prev === undefined) delete document.matches;
                else document.matches = prev;
            }
        }
    });

