    ackTest('wordDiff handles multiline text', () => {
        const d = wordDiff('line one\nline two', 'line one\nline three');
        const del = d.filter((x) => x.type === 'del').map((x) => x.text);
        const add = d.filter((x) => x.type === 'add').map((x) => x.text);
        ackAssert(del.includes('two'), 'deleted "two"');
        ackAssert(add.includes('three'), 'added "three"');
    });

    ackTest('wordDiff handles punctuation change', () => {
        const d = wordDiff('Hello, world!', 'Hello; world.');
        ackAssert(
            d.some((x) => x.type === 'del'),
            'detects removed punctuated word',
        );
        ackAssert(
            d.some((x) => x.type === 'add'),
            'detects added punctuated word',
        );
    });

    ackTest('wordDiff preserves whitespace tokens', () => {
        const d = wordDiff('a  b', 'a  b');
        // All tokens should be 'same'
        ackAssert(
            d.every((x) => x.type === 'same'),
            'identical text has no changes',
        );
    });

    ackTest('wordDiff handles markdown link changes', () => {
        const d = wordDiff('See [link](http://old.com)', 'See [link](http://new.com)');
        ackAssert(
            d.some((x) => x.type === 'del'),
            'old URL removed',
        );
        ackAssert(
            d.some((x) => x.type === 'add'),
            'new URL added',
        );
    });

    ackTest('wordDiff handles single character change', () => {
        const d = wordDiff('cat', 'bat');
        ackEq(d.filter((x) => x.type === 'del').length, 1);
        ackEq(d.filter((x) => x.type === 'add').length, 1);
    });

    ackTest('wordDiff with completely different text', () => {
        const d = wordDiff('alpha beta', 'gamma delta');
        const del = d.filter((x) => x.type === 'del');
        const add = d.filter((x) => x.type === 'add');
        ackAssert(del.length >= 1, 'at least 1 deletion group');
        ackAssert(add.length >= 1, 'at least 1 addition group');
        ackAssert(
            del.some((x) => x.text.includes('alpha')),
            'old text removed',
        );
        ackAssert(
            add.some((x) => x.text.includes('gamma')),
            'new text added',
        );
    });

    ackTest('wordDiff with unicode characters', () => {
        const d = wordDiff('naïve café', 'naive cafe');
        ackAssert(
            d.some((x) => x.type === 'del'),
            'unicode originals detected',
        );
        ackAssert(
            d.some((x) => x.type === 'add'),
            'ascii replacements detected',
        );
    });

