    ackTest('fetch format produces git fetch + switch command', () => {
        const f = SHA_FORMATS.find((f) => f.key === 'fetch');
        const result = f.fmt('abc123def456', { owner: 'bitcoin', repo: 'bitcoin', pr: '100' });
        ackAssert(result.startsWith('git fetch origin abc123def456'), 'starts with git fetch');
        ackAssert(result.includes('git switch --detach FETCH_HEAD'), 'includes switch detach');
    });

    ackTest('parent format is handled asynchronously via copySHA helper', () => {
        const f = SHA_FORMATS.find((f) => f.key === 'parent');
        ackEq(
            f.fmt('abc123', { owner: 'bitcoin', repo: 'bitcoin', pr: '100' }),
            null,
            'parent fmt is resolved asynchronously',
        );
    });

    ackTest('ghco format produces gh pr co command with rebase', () => {
        const f = SHA_FORMATS.find((f) => f.key === 'ghco');
        const origBase = getReviewBaseBranch;
        getReviewBaseBranch = () => 'main';
        try {
            const result = f.fmt('abc', { owner: 'bitcoin', repo: 'bitcoin', pr: '42' });
            ackAssert(result.includes('gh pr co'), 'has gh pr co');
            ackAssert(result.includes('https://github.com/bitcoin/bitcoin/pull/42'), 'has full PR URL');
            ackAssert(result.includes('--force'), 'has --force flag');
            ackAssert(result.includes('REMOTE=$(git remote | grep -qx upstream && echo upstream || echo origin)'), 'sets remote fallback');
            ackAssert(result.includes('&& git pull --rebase "$REMOTE" main'), 'has rebase');
            ackAssert(!result.includes("'main'"), 'does not quote simple branch names');
        } finally {
            getReviewBaseBranch = origBase;
        }
    });

