    ackTest('no querySelector guard-vs-insertion mismatches in codebase', () => {
        // Pattern: if X.querySelector('.ack-FOO') is used as guard,
        // then .ack-FOO must be inserted as a descendant of X, not as a sibling.
        // Note: addQuickCommentActions uses a different guard pattern (dataset + length),
        // so it correctly has 3 querySelector-based guards.
        const source = _ackSource;
        const testSuiteIdx = source.indexOf('const _ackTests = []');
        const mainSource = testSuiteIdx > 0 ? source.slice(0, testSuiteIdx) : source;
        // Match simple guards like:
        //   if (toolbar.querySelector('.ack-foo')) return;
        //   if (c.el.querySelector('.ack-foo')) continue;
        // capturing the *full* variable expression on the left.
        const guardPattern =
            /([A-Za-z_$][\w$]*(?:\.[A-Za-z_$][\w$]*)*)\.querySelector\(['"]\.(ack-[\w-]+)['"]\)\)\s*(continue|return)/g;
        const guards = [];
        let m;
        while ((m = guardPattern.exec(mainSource)) !== null) {
            guards.push({ variable: m[1], className: m[2], action: m[3] });
        }
        // Keep this non-brittle: guard count can change as features evolve,
        // but should stay within a small expected band.
        ackAssert(
            guards.length >= 4 && guards.length <= 6,
            `expected 4-6 querySelector guards, found ${guards.length}: ${JSON.stringify(guards)}`,
        );
        for (const g of guards) {
            ackNeq(
                g.variable,
                'commitHeader',
                `guard on commitHeader for .${g.className} would miss .after() siblings`,
            );
        }
    });

